SKILL = {'name': 'test_driven_development', 'keywords': ['testing', 'unit tests', 'edge cases', 'validation', 'type checking', 'division by zero', 'assertions'], 'prompt_fragment': 'Implement test-driven development for arithmetic operations with comprehensive coverage of valid, invalid, and edge cases. Define type-safe functions with proper signatures and validation. Include unit tests for normal operations, boundary values, and error handling. Verify function contracts using inspection and assertions. Ensure division raises ValueError on zero denominator and type validation returns correct booleans.', 'example_code': 'from typing import Union\n\nNumber = Union[int, float]\n\ndef suma(a: Number, b: Number) -> Number:\n    return a + b\n\ndef division(a: Number, b: Number) -> Number:\n    if b == 0:\n        raise ValueError("Division by zero not allowed")\n    return a / b\n\ndef validar_tipo(valor: object, tipos_permitidos: tuple) -> bool:\n    return isinstance(valor, tipos_permitidos)\n\n# Unit tests\nimport unittest\n\nclass TestOperaciones(unittest.TestCase):\n    def test_division_by_zero(self):\n        with self.assertRaises(ValueError):\n            division(1, 0)\n    \n    def test_validar_tipo_valid(self):\n        self.assertTrue(validar_tipo(42, (int, float)))\n    \n    def test_validar_tipo_invalid(self):\n        self.assertFalse(validar_tipo("x", (int,)))', 'language': 'python'}
